export type InitInput = RequestInfo | URL | Response | BufferSource | WebAssembly.Module;

export interface InitOutput {
  readonly memory: WebAssembly.Memory;
  readonly __wbg_parserconfig_free: (a: number) => void;
  readonly __wbg_get_parserconfig_interpolate: (a: number) => number;
  readonly __wbg_set_parserconfig_interpolate: (a: number, b: number) => void;
  readonly __wbg_get_parserconfig_execution: (a: number) => number;
  readonly __wbg_set_parserconfig_execution: (a: number, b: number) => void;
  readonly __wbg_get_parserconfig_single_whitespace: (a: number) => number;
  readonly __wbg_set_parserconfig_single_whitespace: (a: number, b: number) => void;
  readonly __wbg_get_parserconfig_multiple_whitespace: (a: number) => number;
  readonly __wbg_set_parserconfig_multiple_whitespace: (a: number, b: number) => void;
  readonly parserconfig_new: (a: number, b: number, c: number, d: number, e: number, f: number, g: number, h: number, i: number, j: number) => number;
  readonly parserconfig_opening_tag: (a: number, b: number) => void;
  readonly parserconfig_set_opening_tag: (a: number, b: number, c: number) => void;
  readonly parserconfig_closing_tag: (a: number, b: number) => void;
  readonly parserconfig_set_closing_tag: (a: number, b: number, c: number) => void;
  readonly parserconfig_global_var: (a: number, b: number) => void;
  readonly parserconfig_set_global_var: (a: number, b: number, c: number) => void;
  readonly __wbg_renderer_free: (a: number) => void;
  readonly renderer_new: (a: number) => number;
  readonly renderer_render_content: (a: number, b: number, c: number, d: number, e: number) => void;
  readonly __wbindgen_malloc: (a: number) => number;
  readonly __wbindgen_realloc: (a: number, b: number, c: number) => number;
  readonly __wbindgen_add_to_stack_pointer: (a: number) => number;
  readonly __wbindgen_free: (a: number, b: number) => void;
  readonly __wbindgen_exn_store: (a: number) => void;
}

export type SyncInitInput = BufferSource | WebAssembly.Module;
/**
* Instantiates the given `module`, which can either be bytes or
* a precompiled `WebAssembly.Module`.
*
* @param {SyncInitInput} module
*
* @returns {InitOutput}
*/
export function initSync(module: SyncInitInput): InitOutput;

/**
* If `module_or_path` is {RequestInfo} or {URL}, makes a request and
* for everything else, calls `WebAssembly.instantiate` directly.
*
* @param {InitInput | Promise<InitInput>} module_or_path
*
* @returns {Promise<InitOutput>}
*/
export default function init (module_or_path?: InitInput | Promise<InitInput>): Promise<InitOutput>;
